import React, { useState } from 'react';

function Swipe({ user, onLogout, isSubscribed, onSubscribe, onProfile }) {
  const [messagesLeft, setMessagesLeft] = useState(3);
  const [currentUserIndex, setCurrentUserIndex] = useState(0);
  const [showSubscription, setShowSubscription] = useState(false);

  const users = [
    { id: 1, name: 'Sarah', age: 24, city: 'Alger', image: '👩', bio: '💕 À la recherche de l\'amour' },
    { id: 2, name: 'Karim', age: 27, city: 'Oran', image: '👨', bio: '❤️ Sportif et aventurier' },
    { id: 3, name: 'Leila', age: 23, city: 'Constantine', image: '👩', bio: '💖 Passionnée de voyage' },
    { id: 4, name: 'Youssef', age: 26, city: 'Annaba', image: '👨', bio: '❤️ Cherche l\'âme sœur' },
  ];

  const currentUser = users[currentUserIndex];

  const nextUser = () => setCurrentUserIndex((currentUserIndex + 1) % users.length);

  const handleLike = () => {
    if (messagesLeft <= 0 && !isSubscribed) { setShowSubscription(true); return; }
    setMessagesLeft(messagesLeft - 1);
    nextUser();
  };

  const handleDislike = () => nextUser();

  const handleSendMessage = () => {
    if (messagesLeft <= 0 && !isSubscribed) { setShowSubscription(true); return; }
    alert(`💕 Message envoyé à ${currentUser.name}!`);
    setMessagesLeft(messagesLeft - 1);
  };

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <h1 style={styles.title}>💕 Chatalgerie</h1>
        <div style={styles.headerRight}>
          <span style={styles.messagesLeft}>💬 {messagesLeft} messages</span>
          <button style={styles.profileBtn} onClick={onProfile}>👤</button>
          <button style={styles.logoutBtn} onClick={onLogout}>🚪</button>
        </div>
      </div>
      <div style={styles.card}>
        <div style={styles.userImage}><span style={styles.emoji}>{currentUser.image}</span></div>
        <div style={styles.userInfo}>
          <h2 style={styles.userName}>{currentUser.name}, {currentUser.age}</h2>
          <p style={styles.userCity}>📍 {currentUser.city}</p>
          <p style={styles.userBio}>{currentUser.bio}</p>
        </div>
        <div style={styles.actions}>
          <button style={styles.dislikeBtn} onClick={handleDislike}>❌</button>
          <button style={styles.likeBtn} onClick={handleLike}>❤️</button>
        </div>
      </div>
      <button style={styles.messageBtn} onClick={handleSendMessage}>💬 Envoyer un message</button>
      {showSubscription && (
        <div style={styles.subscriptionOverlay}>
          <div style={styles.subscriptionBox}>
            <h2>💎 Messages épuisés!</h2>
            <p>Vous avez utilisé vos 3 messages gratuits.</p>
            <p style={styles.subscriptionText}>Abonnez-vous pour des messages illimités ❤️</p>
            <button style={styles.subscribeNowBtn} onClick={onSubscribe}>💕 S'abonner maintenant</button>
            <button style={styles.closeSubBtn} onClick={() => setShowSubscription(false)}>✕</button>
          </div>
        </div>
      )}
      <div style={styles.hearts}><span style={styles.heart}>❤️</span><span style={styles.heart}>💕</span><span style={styles.heart}>❤️</span></div>
    </div>
  );
}

const styles = {
  container: { display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', minHeight: '100vh', background: 'linear-gradient(135deg, #FFB6C1 0%, #87CEEB 100%)', fontFamily: 'Arial, sans-serif', padding: '20px' },
  header: { width: '100%', maxWidth: '400px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' },
  title: { fontSize: '1.8rem', fontWeight: 'bold', background: 'linear-gradient(45deg, #FF69B4, #4A90D9)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' },
  headerRight: { display: 'flex', alignItems: 'center', gap: '10px' },
  messagesLeft: { backgroundColor: 'rgba(255,255,255,0.9)', padding: '8px 15px', borderRadius: '20px', fontWeight: 'bold', color: '#333', fontSize: '0.9rem' },
  profileBtn: { backgroundColor: 'rgba(255,255,255,0.9)', border: 'none', borderRadius: '50%', width: '40px', height: '40px', fontSize: '1.2rem', cursor: 'pointer' },
  logoutBtn: { backgroundColor: 'rgba(255,255,255,0.9)', border: 'none', borderRadius: '50%', width: '40px', height: '40px', fontSize: '1.2rem', cursor: 'pointer' },
  card: { backgroundColor: 'white', borderRadius: '24px', padding: '30px', width: '100%', maxWidth: '400px', boxShadow: '0 20px 60px rgba(0,0,0,0.15)', textAlign: 'center' },
  userImage: { width: '150px', height: '150px', borderRadius: '50%', backgroundColor: '#f0f0f0', margin: '0 auto 20px', display: 'flex', justifyContent: 'center', alignItems: 'center', border: '4px solid #FF69B4' },
  emoji: { fontSize: '70px' },
  userInfo: { marginBottom: '20px' },
  userName: { fontSize: '1.8rem', fontWeight: 'bold', color: '#333', marginBottom: '5px' },
  userCity: { color: '#888', fontSize: '1rem', marginBottom: '10px' },
  userBio: { color: '#666', fontSize: '1rem', fontStyle: 'italic' },
  actions: { display: 'flex', justifyContent: 'center', gap: '30px', marginTop: '20px' },
  dislikeBtn: { backgroundColor: '#FF6B6B', border: 'none', borderRadius: '50%', width: '60px', height: '60px', fontSize: '30px', cursor: 'pointer', boxShadow: '0 4px 15px rgba(255,107,107,0.3)' },
  likeBtn: { backgroundColor: '#FF1493', border: 'none', borderRadius: '50%', width: '60px', height: '60px', fontSize: '30px', cursor: 'pointer', boxShadow: '0 4px 15px rgba(255,20,147,0.3)' },
  messageBtn: { width: '100%', maxWidth: '400px', padding: '15px', marginTop: '20px', borderRadius: '15px', border: 'none', backgroundColor: 'white', color: '#333', fontSize: '1.1rem', fontWeight: 'bold', cursor: 'pointer', boxShadow: '0 4px 20px rgba(0,0,0,0.1)' },
  subscriptionOverlay: { position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, backgroundColor: 'rgba(0,0,0,0.7)', backdropFilter: 'blur(10px)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 999 },
  subscriptionBox: { backgroundColor: 'white', borderRadius: '30px', padding: '40px', maxWidth: '400px', width: '90%', textAlign: 'center', position: 'relative' },
  subscriptionText: { fontSize: '1.2rem', fontWeight: 'bold', color: '#FF1493', margin: '15px 0' },
  subscribeNowBtn: { width: '100%', padding: '15px', borderRadius: '15px', border: 'none', background: 'linear-gradient(45deg, #FF6B6B, #FF1493)', color: 'white', fontSize: '1.2rem', fontWeight: 'bold', cursor: 'pointer' },
  closeSubBtn: { position: 'absolute', top: '15px', right: '20px', background: 'none', border: 'none', fontSize: '25px', cursor: 'pointer', color: '#999' },
  hearts: { marginTop: '20px', display: 'flex', gap: '15px' },
  heart: { fontSize: '1.5rem', animation: 'pulse 1.5s infinite' },
};

const styleSheet = document.createElement('style');
styleSheet.textContent = `@keyframes pulse { 0% { transform: scale(1); } 50% { transform: scale(1.3); } 100% { transform: scale(1); } }`;
document.head.appendChild(styleSheet);

export default Swipe;
